record.field:
for record in records:
    record.message_post(
        body=(
            "<b>Commande confirmee - A preparer</b><br/>"
            "Commande : <b>%(name)s</b><br/>"
            "Client : <b>%(partner)s</b><br/>"
            "Montant : <b>%(amount).2f MAD</b><br/>"
            "Lignes : %(lines)d produit(s)<br/>"
            "<em>Le magasinier doit verifier le stock et preparer le bon de livraison.</em>"
        ) % {
            'name': record.name,
            'partner': record.partner_id.name,
            'amount': record.amount_total,
            'lines': len(record.order_line),
        },
        message_type='comment',
        subtype_xmlid='mail.mt_note',
    )
    groups_to_notify = [
        env.ref('stock.group_stock_manager', raise_if_not_found=False),
        env.ref('parabox_logistics_tracking.group_parabox_magasinier', raise_if_not_found=False),
        env.ref('parabox_logistics_tracking.group_parabox_direction', raise_if_not_found=False),
    ]
    partner_ids = list(set(
        pid
        for grp in groups_to_notify if grp
        for pid in grp.users.mapped('partner_id').ids
    ))
    if partner_ids:
        env['mail.message'].create({
            'message_type': 'notification',
            'body': (
                "<b>Nouvelle commande a preparer</b><br/>"
                "Commande <b>%(name)s</b> — Client : %(partner)s<br/>"
                "Montant : %(amount).2f MAD"
            ) % {
                'name': record.name,
                'partner': record.partner_id.name,
                'amount': record.amount_total,
            },
            'res_id': record.id,
            'model': 'sale.order',
            'subtype_id': env.ref('mail.mt_comment').id,
            'notification_ids': [(0, 0, {
                'notification_type': 'inbox',
                'res_partner_id': pid,
                'notification_status': 'ready',
            }) for pid in partner_ids],
        })

for record in records:
    sale_order = record.sale_id or False
    groups_to_notify = [
        env.ref('sales_team.group_sale_salesman', raise_if_not_found=False),
        env.ref('parabox_logistics_tracking.group_parabox_commercial', raise_if_not_found=False),
        env.ref('parabox_logistics_tracking.group_parabox_direction', raise_if_not_found=False),
    ]
    partner_ids = list(set(
        pid
        for grp in groups_to_notify if grp
        for pid in grp.users.mapped('partner_id').ids
    ))
    if partner_ids:
        env['mail.message'].create({
            'message_type': 'notification',
            'body': (
                "<b>Bon de livraison valide</b><br/>"
                "BL : <b>%(name)s</b><br/>"
                "Client : %(partner)s<br/>"
                "%(order_info)s"
            ) % {
                'name': record.name,
                'partner': record.partner_id.name if record.partner_id else '—',
                'order_info': ("Commande : %s" % sale_order.name) if sale_order else '',
            },
            'res_id': record.id,
            'model': 'stock.picking',
            'subtype_id': env.ref('mail.mt_comment').id,
            'notification_ids': [(0, 0, {
                'notification_type': 'inbox',
                'res_partner_id': pid,
                'notification_status': 'ready',
            }) for pid in partner_ids],
        })

